import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testGetNullStringWhenNullStringIsNull() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
        assertNull(format.getNullString());
    }

    @Test
    void testGetNullStringWhenNullStringIsSet() {
        CSVFormat format = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                "NULL", null, null, false, false, false, false, false, false);
        assertEquals("NULL", format.getNullString());
    }

    @Test
    void testGetNullStringViaWithNullString() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("testNull");
        assertEquals("testNull", format.getNullString());
    }

    @Test
    void testGetNullStringOnPredefinedConstants() {
        assertNull(CSVFormat.DEFAULT.getNullString());
        assertEquals("\\N", CSVFormat.MYSQL.getNullString());
        assertEquals("", CSVFormat.POSTGRESQL_CSV.getNullString());
        assertEquals("\\N", CSVFormat.POSTGRESQL_TEXT.getNullString());
    }
}
